import sys
import bisect

def solve():
    import sys
    input = sys.stdin.readline
    N, Q = map(int, input().split())
    A = list(map(int, input().split()))
    queries = [tuple(map(int, input().split())) for _ in range(Q)]

    # Preprocess the array to find LIS up to each position
    sorted_unique = sorted(set(A))
    value_to_idx = {val: i for i, val in enumerate(sorted_unique)}

    class FenwickTree:
        def __init__(self, size):
            self.n = size
            self.tree = [0] * (self.n + 2)

        def update(self, idx, value):
            while idx <= self.n:
                if self.tree[idx] < value:
                    self.tree[idx] = value
                else:
                    break
                idx += idx & -idx

        def query(self, idx):
            res = 0
            while idx > 0:
                res = max(res, self.tree[idx])
                idx -= idx & -idx
            return res

    lis_length = [0] * N
    ft = FenwickTree(len(sorted_unique))
    for i in range(N):
        val = A[i]
        idx_val = value_to_idx[val]
        # Find the largest index with value < val
        left, right = 0, len(sorted_unique) - 1
        pos = -1
        while left <= right:
            mid = (left + right) // 2
            if sorted_unique[mid] < val:
                pos = mid
                left = mid + 1
            else:
                right = mid - 1
        if pos != -1:
            max_len = ft.query(pos + 1)
        else:
            max_len = 0
        lis_length[i] = max_len + 1
        ft.update(idx_val + 1, lis_length[i])

    # Precompute prefix max of lis_length
    prefix_max = [0] * (N + 1)
    for i in range(N):
        prefix_max[i+1] = max(prefix_max[i], lis_length[i])

    res = []
    for R, X in queries:
        # Find the largest index with value <= X
        left, right = 0, len(sorted_unique) - 1
        pos = -1
        while left <= right:
            mid = (left + right) // 2
            if sorted_unique[mid] <= X:
                pos = mid
                left = mid + 1
            else:
                right = mid - 1
        if pos == -1:
            res.append(0)
        else:
            # Binary search for the highest position <= R with value <= X
            left_search, right_search = 0, R - 1
            best_pos = -1
            while left_search <= right_search:
                mid_search = (left_search + right_search) // 2
                if A[mid_search] <= X:
                    best_pos = mid_search
                    left_search = mid_search + 1
                else:
                    right_search = mid_search - 1
            if best_pos == -1:
                res.append(0)
            else:
                res.append(prefix_max[best_pos + 1])

    print('\n'.join(map(str, res)))

